// Validate required fields from webhook payload
const body = $input.first().json;
const binary = $input.first().binary;

if (!binary || !binary.data) {
  throw new Error('No PDF file found in request. Ensure field name is "data".');
}

if (!body.student_email) {
  throw new Error('student_email is required in form fields.');
}

if (!body.course_name) {
  throw new Error('course_name is required.');
}

if (!body.semester_start) {
  throw new Error('semester_start (YYYY-MM-DD) is required.');
}

// Generate unique plan ID
const planId = 'plan_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);

return [{
  json: {
    plan_id: planId,
    student_email: body.student_email,
    student_name: body.student_name || 'Student',
    course_name: body.course_name,
    semester_start: body.semester_start,
    upload_timestamp: new Date().toISOString()
  },
  binary: binary
}];

// Merge Drive upload result back with student metadata
const prevItems = $('Code: Validate & Prep').all();
const driveItem = $input.first();

return [{
  json: {
    ...prevItems[0].json,
    drive_file_id: driveItem.json.id,
    drive_web_link: driveItem.json.webViewLink
  },
  binary: prevItems[0].binary
}];

// Merge PDF text with student metadata
const meta = $('Code: Merge Drive Meta').first().json;
const extracted = $input.first().json;

const syllabusText = extracted.text || '';

if (!syllabusText || syllabusText.trim().length < 100) {
  throw new Error('PDF text extraction failed or returned too little content. Ensure the PDF is not scanned/image-only.');
}

// Truncate to ~12000 chars to stay within token limits (adjust as needed)
const truncatedText = syllabusText.slice(0, 12000);

return [{
  json: {
    ...meta,
    syllabus_text: truncatedText,
    full_char_count: syllabusText.length
  }
}];

// Parse AI response and merge everything
const meta = $('Code: Merge PDF Text').first().json;
const aiResponse = $input.first().json;

let parsedSyllabus;
try {
  // OpenAI with json_object format returns content as string
  const content = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || aiResponse.content || '';
  parsedSyllabus = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error('Failed to parse AI topic extraction response as JSON: ' + e.message);
}

if (!parsedSyllabus.topics || parsedSyllabus.topics.length === 0) {
  throw new Error('AI returned no topics. Check PDF text quality.');
}

return [{
  json: {
    ...meta,
    parsed_syllabus: parsedSyllabus,
    topics_count: parsedSyllabus.topics.length,
    exams_count: (parsedSyllabus.exams || []).length
  }
}];

// Parse schedule AI response + compute week dates
const meta = $('Code: Parse Topics Response').first().json;
const aiResponse = $input.first().json;

let scheduleData;
try {
  const content = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || aiResponse.content || '';
  scheduleData = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error('Failed to parse schedule AI response: ' + e.message);
}

if (!scheduleData.schedule || scheduleData.schedule.length !== 15) {
  throw new Error(`Schedule must have exactly 15 weeks. Got: ${scheduleData.schedule?.length}`);
}

// Compute actual calendar dates for each week
const startDate = new Date(meta.semester_start);
// Find the next Monday from start date
const dayOfWeek = startDate.getDay();
const daysUntilMonday = dayOfWeek === 0 ? 1 : (dayOfWeek === 1 ? 0 : 8 - dayOfWeek);
startDate.setDate(startDate.getDate() + daysUntilMonday);

const fullSchedule = scheduleData.schedule.map((week, idx) => {
  const weekStart = new Date(startDate);
  weekStart.setDate(startDate.getDate() + (idx * 7));
  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 4); // Friday

  return {
    ...week,
    plan_id: meta.plan_id,
    student_email: meta.student_email,
    student_name: meta.student_name,
    course_name: meta.course_name,
    week_start_date: weekStart.toISOString().split('T')[0],
    week_end_date: weekEnd.toISOString().split('T')[0],
    week_start_iso: weekStart.toISOString(),
    email_sent: false
  };
});

// Also return combined metadata for sheet storage
return [{
  json: {
    plan_id: meta.plan_id,
    student_email: meta.student_email,
    student_name: meta.student_name,
    course_name: meta.course_name,
    semester_start: meta.semester_start,
    drive_file_id: meta.drive_file_id,
    drive_web_link: meta.drive_web_link,
    topics_json: JSON.stringify(meta.parsed_syllabus.topics),
    schedule_json: JSON.stringify(fullSchedule),
    full_schedule: fullSchedule,
    topics_count: meta.topics_count,
    status: 'active',
    created_at: new Date().toISOString(),
    current_week: 1,
    next_email_date: fullSchedule[0].week_start_date
  }
}];

// Extract the full schedule array for loop iteration
const data = $input.first().json;
return data.full_schedule.map(week => ({ json: week }));

