const aiResponse = $input.first();

// Find matching student (they should be in order)
const currentIndex = $itemIndex || 0;
const student = studentData[currentIndex]?.json || studentData[0]?.json;

const emailHtml = aiResponse.json.message?.content 
  || aiResponse.json.choices?.[0]?.message?.content 
  || aiResponse.json.content 
  || '<p>Weekly study plan update — check your calendar!</p>';

return [{
  json: {
    ...student,
    email_html: emailHtml
  }
}];

// Calculate next email date and updated week number
const data = $input.first().json;
const nextWeekNum = (parseInt(data.current_week_num) || 1) + 1;
const nextEmailDate = new Date();
nextEmailDate.setDate(nextEmailDate.getDate() + 7);

return [{
  json: {
    plan_id: data.plan_id,
    student_email: data.student_email,
    new_week_num: nextWeekNum,
    new_status: nextWeekNum > 15 ? 'completed' : 'active',
    new_next_email: nextEmailDate.toISOString().split('T')[0],
    email_sent_week: data.current_week_num
  }
}];

// Log successful execution for monitoring
const data = $input.first().json;
console.log(`[S2S Engine] Weekly email sent successfully:`, {
  student: data.student_email,
  week: data.email_sent_week,
  next_email: data.new_next_email,
  status: data.new_status,
  timestamp: new Date().toISOString()
});
return $input.all();
